import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface FlightData {
  flight: {
    airline: string;
    flightNumber: string;
    departure: {
      airport: string;
      scheduledTime: string;
      actualTime: string;
      gate: string;
      status: string;
    };
    arrival: {
      airport: string;
      scheduledTime: string;
      estimatedTime: string;
      gate: string;
      status: string;
    };
    delay: {
      duration: string;
      reason: string;
    };
  };
}

export default function Widget() {
  const { flight } = response.data as FlightData;
  const { airline, flightNumber, departure, arrival, delay } = flight;
  const isDelayed = departure.status.toLowerCase() === 'delayed';

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#007BFF' }}>
              {airline} {flightNumber}
            </Typography>
            <Stack direction="row" spacing={1} alignItems="center">
              <Typography variant="body2" color="text.secondary">
                Departure:
              </Typography>
              <Chip label={`${departure.airport} - Gate ${departure.gate}`} sx={{ fontSize: '11px', px: 1 }} />
              {isDelayed && (
                <Tooltip title={`Delayed: ${delay.reason}`}>
                  <Info fontSize="small" sx={{ color: '#FF5733' }} />
                </Tooltip>
              )}
            </Stack>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Scheduled: {departure.scheduledTime}, Actual: {departure.actualTime}
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" spacing={1} alignItems="center">
              <Typography variant="body2" color="text.secondary">
                Arrival:
              </Typography>
              <Chip label={`${arrival.airport} - Gate ${arrival.gate}`} sx={{ fontSize: '11px', px: 1 }} />
            </Stack>
            <Typography variant="body2" sx={{ mt: 0.5 }}>
              Scheduled: {arrival.scheduledTime}, Estimated: {arrival.estimatedTime}
            </Typography>
          </Box>

          <Stack direction="row" spacing={1} alignItems="center">
            <Typography variant="body2" color="text.secondary">
              Flight Status:
            </Typography>
            <Chip label={departure.status} sx={{ backgroundColor: isDelayed ? '#FF5733' : '#007BFF', color: '#FFFFFF', fontSize: '11px' }} />
          </Stack>

          {isDelayed && (
            <Box>
              <Typography variant="body2" color="text.secondary">
                Delay Duration: {delay.duration}
              </Typography>
            </Box>
          )}
        </Stack>
      </CardContent>
    </Card>
  );
}
